class Solution:
    def minStable(self, nums: List[int], maxC: int) -> int:
        def gcd(a, b):
            while b:
                a, b = b, a % b
            return a

        n = len(nums)
        dp = [[0] * (maxC + 1) for _ in range(n + 1)]
        for i in range(1, n + 1):
            for j in range(1, min(i, maxC) + 1):
                dp[i][j] = dp[i - 1][j]
                for k in range(i - 1, max(0, i - 10)):
                    if gcd(nums[k], nums[i - 1]) >= 2:
                        dp[i][j] = max(dp[i][j], dp[k][j - 1] + 1)
        return max(dp[n])
